import{c as t,Q as n,j as a,m as o}from"./chunks/framework.BXc4yaFE.js";const c=JSON.parse('{"title":"LLM Powered Autonomous Agents","description":"","frontmatter":{"title":"LLM Powered Autonomous Agents","authors":"Lilian Weng（OpenAI Research）","published":"2023-06-23T00:00:00.000Z","source":"https://lilianweng.github.io/posts/2023-06-23-agent/","source_tier":"P"},"headers":[],"relativePath":"research/agent-harness/references/2023-06-23-lilian-weng-llm-agents.md","filePath":"research/agent-harness/references/2023-06-23-lilian-weng-llm-agents.md","lastUpdated":1779894392000}'),r={name:"research/agent-harness/references/2023-06-23-lilian-weng-llm-agents.md"};function i(l,e,s,g,h,d){return n(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="llm-powered-autonomous-agents" tabindex="-1">LLM Powered Autonomous Agents <a class="header-anchor" href="#llm-powered-autonomous-agents" aria-label="Permalink to &quot;LLM Powered Autonomous Agents&quot;">​</a></h1><ul><li><strong>作者</strong>: Lilian Weng（OpenAI Research）</li><li><strong>URL</strong>: <a href="https://lilianweng.github.io/posts/2023-06-23-agent/" target="_blank" rel="noreferrer">https://lilianweng.github.io/posts/2023-06-23-agent/</a></li><li><strong>發表</strong>: 2023-06-23</li><li><strong>收錄日期</strong>: 2026-05-01</li><li><strong>重要性</strong>: Priority B — 業界標準入門文章；Planning-Memory-Tools 三層框架的經典定義</li></ul><hr><h2 id="核心框架-三層架構" tabindex="-1">核心框架：三層架構 <a class="header-anchor" href="#核心框架-三層架構" aria-label="Permalink to &quot;核心框架：三層架構&quot;">​</a></h2><h3 id="_1-planning-層" tabindex="-1">1. Planning 層 <a class="header-anchor" href="#_1-planning-層" aria-label="Permalink to &quot;1. Planning 層&quot;">​</a></h3><ul><li><strong>Task Decomposition</strong>: 複雜任務自動分解為可執行的子目標 <ul><li>Chain of Thought (CoT): 逐步推理</li><li>Tree of Thoughts (ToT): 樹狀探索多條推理路徑</li></ul></li><li><strong>Self-Reflection</strong>: 讓 agent 從錯誤中學習 <ul><li>ReAct: Thought-Action-Observation 交錯</li><li>Reflexion: 語言形式的強化學習</li></ul></li></ul><h3 id="_2-memory-層" tabindex="-1">2. Memory 層 <a class="header-anchor" href="#_2-memory-層" aria-label="Permalink to &quot;2. Memory 層&quot;">​</a></h3><table tabindex="0"><thead><tr><th>記憶類型</th><th>對應概念</th><th>技術實現</th></tr></thead><tbody><tr><td>Sensory Memory</td><td>感知輸入</td><td>原始 input（圖像、文字）</td></tr><tr><td>Short-term Memory</td><td>上下文學習</td><td>Context Window（有限長度）</td></tr><tr><td>Long-term Memory</td><td>外部存儲</td><td>向量資料庫（FAISS、ANNOY）</td></tr></tbody></table><p><strong>MIPS 快速近似向量搜尋算法</strong>:</p><ul><li>LSH（Locality-Sensitive Hashing）</li><li>ANNOY（Approximate Nearest Neighbors Oh Yeah）</li><li>FAISS（Facebook AI Similarity Search）</li><li>ScaNN（Scalable Nearest Neighbors）</li></ul><h3 id="_3-tools-action-層" tabindex="-1">3. Tools/Action 層 <a class="header-anchor" href="#_3-tools-action-層" aria-label="Permalink to &quot;3. Tools/Action 層&quot;">​</a></h3><ul><li>讓 agent 調用外部 API 超越訓練數據限制</li><li>MRKL：Modular Reasoning, Knowledge, and Language</li><li>工具使用能力由 LLM 的理解力決定</li></ul><hr><h2 id="核心洞見-對-harness-engineering-最相關" tabindex="-1">核心洞見（對 Harness Engineering 最相關） <a class="header-anchor" href="#核心洞見-對-harness-engineering-最相關" aria-label="Permalink to &quot;核心洞見（對 Harness Engineering 最相關）&quot;">​</a></h2><ol><li><p><strong>Task Decomposition 是 Harness 分層的理論依據</strong>: 複雜任務必須分解才能可靠執行，直接對應 Planner-Generator-Evaluator 三層</p></li><li><p><strong>三層記憶設計是現代 Agent 的基礎</strong>: 短期（context）+ 長期（檢索）混合模式已成行業標準</p></li><li><p><strong>工具可靠性挑戰</strong>: 自然語言界面與外部系統協調的脆性（parsing、錯誤處理）是 Harness 設計的核心考量</p></li><li><p><strong>ReAct 框架是 Agentic Loop 的原型</strong>: Thought-Action-Observation 循環是所有 harness 設計的基礎</p></li><li><p><strong>Context 窗口的有限性驅動 Memory 架構設計</strong>: 短期記憶的限制決定了 Long-term Memory 的必要性</p></li></ol><hr><h2 id="歷史地位" tabindex="-1">歷史地位 <a class="header-anchor" href="#歷史地位" aria-label="Permalink to &quot;歷史地位&quot;">​</a></h2><p>這篇文章是 2023 年定義「LLM Agent」概念的分水嶺，是任何 agent harness 工程師必讀的基礎文獻。Planning-Memory-Tools 框架被後來幾乎所有 agent 框架（LangChain、AutoGPT、BabyAGI 等）採用為設計基礎。</p>',18)])])}const m=t(r,[["render",i]]);export{c as __pageData,m as default};
